from decimal import Decimal, ROUND_HALF_EVEN, InvalidOperation

def parse_edad_monto(edad_txt: str, monto_txt: str) -> dict:
    raw = {"edad": edad_txt, "monto": monto_txt}
    clean = {"edad": None, "monto": None}
    errors = []
    try:
        clean["edad"] = int(edad_txt.strip())
    except ValueError:
        errors.append(f"ERROR en 'edad': no se pudo convertir {edad_txt!r} a int")
    try:
        t = monto_txt.strip()
        if not t:
            raise InvalidOperation
        m = Decimal(t).quantize(Decimal("0.01"), rounding=ROUND_HALF_EVEN)
        clean["monto"] = m
    except (InvalidOperation, ValueError):
        errors.append(f"ERROR en 'monto': no se pudo parsear {monto_txt!r} a Decimal")
    return {"raw": raw, "clean": clean, "errors": errors}

for pair in [("34", "150.50"), ("abc", "99.00"), ("25", "xyz")]:
    print(pair, "→", parse_edad_monto(*pair))

